  React.useEffect(() => {
    console.log(
      '[DrawerContent] open state changed:',
      open,
      'modal ref exists:',
      !!internalRef.current
    );
    if (open) {
      internalRef.current?.present();
    } else {
      internalRef.current?.dismiss();
    }
  }, [open]);

  const handleDismiss = React.useCallback(() => {
